 70	const useCreateDrawerForm = (
 71	  namespace: string,
 72	  subscriptionData: RHELAutomaticSubscriptionData,
 73	  authorizedSSHKey: string,
 74	) => {
 75	  const { updateTabsData, updateVM } = useWizardVMContext();
 76	
 77	  const [isUDNManagedNamespace] = useNamespaceUDN(namespace);
 78	  const [authorizedSSHKeys, updateAuthorizedSSHKeys] = useKubevirtUserSettings('ssh');
 79	  const { featureEnabled: autoUpdateEnabled } = useFeatures(AUTOMATIC_UPDATE_FEATURE_NAME);
 80	  const { featureEnabled: isDisabledGuestSystemLogs } = useFeatures(
 81	    DISABLED_GUEST_SYSTEM_LOGS_ACCESS,
 82	  );
 83	
 84	  const navigate = useNavigate();
 85	  const {
 86	    cdFile,
 87	    diskFile,
 88	    isBootSourceAvailable,
 89	    registryCredentials,
 90	    setVM,
 91	    sshDetails,
 92	    storageClassName,
 93	    storageClassRequired,
 94	    template,
 95	    uploadCDData,
 96	    uploadDiskData,
 97	    vm,
 98	  } = useDrawerContext();
 99	  const { password, username } = registryCredentials;
100	
101	  const { nameField, onVMNameChange } = useCreateVMName();
102	  const isValidVmName = isValidVMName(nameField);
103	
104	  const [isQuickCreating, setIsQuickCreating] = useState(false);
105	  const [isCustomizing, setIsCustomizing] = useState(false);
106	  const [createError, setCreateError] = useState(undefined);
107	  const [models, modelsLoading] = useK8sModels();
108	
109	  const [processedTemplateAccessReview] = useAccessReview({
110	    group: ProcessedTemplatesModel.apiGroup,
111	    namespace,
112	    resource: ProcessedTemplatesModel.plural,
113	    verb: 'create',
114	  });
115	
116	  const storageClassRequiredMissing = storageClassRequired && isEmpty(storageClassName);
117	
118	  const onQuickCreate = async (e: MouseEvent) => {
119	    e.preventDefault();
120	    setIsQuickCreating(true);
121	    setCreateError(undefined);
122	
123	    const addSecret = username && password && bootDiskSourceIsRegistry(template);
124	    const imageSecretName = addRandomSuffix(nameField);
125	
126	    if (addSecret) {
127	      await createSecret({
128	        namespace,
129	        password,
130	        secretName: imageSecretName,
131	        username,
132	      });
133	    }
134	
135	    const templateToProcess = produce(template, (draftTemplate) => {
136	      const vmObject = getTemplateVirtualMachineObject(draftTemplate);
137	
138	      if (vm?.spec?.template) {
139	        ensurePath(vmObject, [
140	          'spec.template.spec.domain.cpu',
141	          'spec.template.spec.domain.memory.guest',
142	        ]);
143	
144	        const { cpu, memory } = getMemoryCPU(vm);
145	        vmObject.spec.template.spec.domain.cpu.cores = cpu?.cores;
146	        vmObject.spec.template.spec.domain.memory.guest = memory;
147	
148	        if (addSecret)
149	          vmObject.spec.dataVolumeTemplates[0].spec.source.registry.secretRef = imageSecretName;
150	
151	        if (!getLabels(vmObject.spec.template)) vmObject.spec.template.metadata.labels = {};
152	
153	        if (!isUDNManagedNamespace)
154	          vmObject.spec.template.metadata.labels[HEADLESS_SERVICE_LABEL] = HEADLESS_SERVICE_NAME;
155	
156	        const modifiedTemplateObjects = template?.objects?.map((obj) =>
157	          obj.kind === VirtualMachineModel.kind ? vmObject : obj,
158	        );
159	
160	        if ('running' in vmObject?.spec) {
161	          vmObject.spec.runStrategy = vmObject.spec.running
162	            ? RUNSTRATEGY_ALWAYS
163	            : RUNSTRATEGY_HALTED;
164	          delete vmObject.spec.running;
165	        }
166	
167	        draftTemplate.objects = modifiedTemplateObjects;
168	
169	        if (sshDetails?.sshSecretName && sshDetails?.applyKeyToProject) {
170	          updateAuthorizedSSHKeys({
171	            ...authorizedSSHKeys,
172	            [namespace]: sshDetails?.sshSecretName,
173	          });
174	        }
175	      }
176	    });
177	
178	    logTemplateFlowEvent(CREATE_VM_BUTTON_CLICKED, template);
179	
180	    try {
181	      const quickCreatedVM = await quickCreateVM({
182	        models,
183	        overrides: {
184	          autoUpdateEnabled,
185	          isDisabledGuestSystemLogs,
186	          isUDNManagedNamespace,
187	          name: nameField,
188	          namespace,
189	          subscriptionData,
190	        },
191	        template: templateToProcess,
192	        uploadData: (processedTemplate) =>
193	          uploadFiles({
194	            cdFile,
195	            diskFile,
196	            namespace,
197	            updateTabsData,
198	            uploadCDData,
199	            uploadDiskData,
200	            vm: getTemplateVirtualMachineObject(processedTemplate),
201	          }),
202	      });
203	
204	      if (sshDetails?.secretOption === SecretSelectionOption.addNew) {
205	        await createSSHSecret(sshDetails?.sshPubKey, sshDetails?.sshSecretName, namespace);
206	      }
207	
208	      setIsQuickCreating(false);
209	      navigate(getResourceUrl({ model: VirtualMachineModel, resource: quickCreatedVM }));
210	      logTemplateFlowEvent(CREATE_VM_SUCCEEDED, templateToProcess);
211	    } catch (error) {
212	      setCreateError(error);
213	      logTemplateFlowEvent(CREATE_VM_FAILED, templateToProcess);
214	    } finally {
215	      setIsQuickCreating(false);
216	    }
217	  };
218	
219	  const onCustomize = async (e: MouseEvent) => {
220	    e.preventDefault();
221	    setIsCustomizing(true);
222	    setCreateError(undefined);
223	
224	    logTemplateFlowEvent(CUSTOMIZE_VM_BUTTON_CLICKED, template);
225	
226	    try {
227	      const processedTemplate = await k8sCreate<V1Template>({
228	        data: { ...template, metadata: { ...template?.metadata, namespace } },
229	        model: ProcessedTemplatesModel,
230	        ns: namespace,
231	        queryParams: {
232	          dryRun: 'All',
233	        },
234	      });
235	
236	      const vmObject = await uploadFiles({
237	        cdFile,
238	        diskFile,
239	        namespace,
240	        updateTabsData,
241	        uploadCDData,
242	        uploadDiskData,
243	        vm: getTemplateVirtualMachineObject(processedTemplate),
244	      });
245	
246	      const updatedVM = produce(vmObject, (vmDraft) => {
247	        ensurePath(vmDraft, [
248	          'spec.template.spec.domain.cpu',
249	          'spec.template.spec.domain.memory.guest',
250	        ]);
251	
252	        vmDraft.metadata.namespace = namespace;
253	        vmDraft.metadata.labels[LABEL_USED_TEMPLATE_NAME] = template.metadata.name;
254	        vmDraft.metadata.labels[LABEL_USED_TEMPLATE_NAMESPACE] = template.metadata.namespace;
255	        const { cpu, memory } = getMemoryCPU(vm);
256	        vmDraft.spec.template.spec.domain.cpu.cores = cpu?.cores;
257	        vmDraft.spec.template.spec.domain.memory.guest = memory;
258	
259	        if ('running' in vmDraft?.spec) {
260	          vmDraft.spec.runStrategy = vmDraft.spec.running ? RUNSTRATEGY_ALWAYS : RUNSTRATEGY_HALTED;
261	          delete vmDraft.spec.running;
262	        }
263	
264	        const updatedVolumes = applyCloudDriveCloudInitVolume(vmObject);
265	        vmDraft.spec.template.spec.volumes = isRHELTemplate(processedTemplate)
266	          ? updateCloudInitRHELSubscription(updatedVolumes, subscriptionData, autoUpdateEnabled)
267	          : updatedVolumes;
268	
269	        const defaultInterface = getInterfaces(vmDraft)?.find(
270	          (iface) => iface.name === DEFAULT_NETWORK_INTERFACE.name,
271	        );
272	
273	        if (isUDNManagedNamespace && defaultInterface) {
274	          delete defaultInterface.masquerade;
275	          defaultInterface.binding = { name: UDN_BINDING_NAME };
276	        }
277	      });
278	
279	      updateTabsData((tabsDataDraft) => {
280	        // additional objects
281	        tabsDataDraft.additionalObjects = processedTemplate.objects.filter((obj) =>
282	          !isEmpty(authorizedSSHKey)
283	            ? obj.kind !== VirtualMachineModel.kind && obj.kind !== SecretModel
284	            : obj.kind !== VirtualMachineModel.kind,
285	        );
286	
287	        // overview
288	        ensurePath(tabsDataDraft, 'overview.templateMetadata');
289	        tabsDataDraft.overview.templateMetadata.name = template.metadata.name;
290	        tabsDataDraft.overview.templateMetadata.namespace = template.metadata.namespace;
291	        tabsDataDraft.overview.templateMetadata.osType = getTemplateOS(template);
292	        tabsDataDraft.overview.templateMetadata.displayName = getAnnotation(
293	          template,
294	          ANNOTATIONS.displayName,
295	        );
296	
297	        ensurePath(tabsDataDraft, 'disks.rootDiskRegistryCredentials');
298	        tabsDataDraft.disks.rootDiskRegistryCredentials = {
299	          password: encodeSecretKey(password),
300	          username: encodeSecretKey(username),
301	        };
302	      });
303	
304	      updateTabsData((currentTabsData) => {
305	        currentTabsData.authorizedSSHKey = sshDetails?.sshSecretName;
306	        currentTabsData.applySSHToSettings = sshDetails?.applyKeyToProject;
307	      });
308	
309	      // update context vm
310	      await updateVM(
311	        !isEmpty(authorizedSSHKey) ? addSecretToVM(updatedVM, authorizedSSHKey) : updatedVM,
312	      );
313	      navigate(`/k8s/ns/${namespace}/catalog/template/review`);
314	    } catch (error) {
315	      setCreateError(error);
316	      logTemplateFlowEvent(CUSTOMIZE_VM_FAILED, template);
317	    }
318	    setIsCustomizing(false);
319	  };
320	
321	  const onChangeStartVM = (checked: boolean) => {
322	    setVM(
323	      produce(vm, (draftVM) => {
324	        delete draftVM.spec.running;
325	        draftVM.spec.runStrategy = checked ? RUNSTRATEGY_ALWAYS : RUNSTRATEGY_HALTED;
326	      }),
327	    );
328	  };
329	
330	  const onChangeFolder = (folderName: string) => {
331	    setVM(
332	      produce(vm, (draftVM) => {
333	        if (folderName && folderName !== getLabel(vm, VM_FOLDER_LABEL))
334	          draftVM.metadata.labels = { ...vm?.metadata?.labels, [VM_FOLDER_LABEL]: folderName };
335	      }),
336	    );
337	  };
338	
339	  const credentialsValid = (username && password) || (!username && !password);
340	
341	  return {
342	    createError,
343	    folder: getLabel(vm, VM_FOLDER_LABEL),
344	    isCustomizeDisabled:
345	      !processedTemplateAccessReview || !credentialsValid || isCustomizing || !isValidVmName,
346	    isCustomizeLoading: isCustomizing || modelsLoading,
347	    isQuickCreateDisabled:
348	      !isBootSourceAvailable ||
349	      isQuickCreating ||
350	      !nameField ||
351	      isEmpty(models) ||
352	      !allRequiredParametersAreFulfilled(template) ||
353	      !hasValidSource(template) ||
354	      storageClassRequiredMissing ||
355	      !isValidVmName ||
356	      !credentialsValid,
357	    isQuickCreateLoading: isQuickCreating || modelsLoading,
358	    nameField,
359	    onChangeFolder,
360	    onChangeStartVM,
361	    onCustomize,
362	    onQuickCreate,
363	    onVMNameChange,
364	    runStrategy: vm?.spec?.runStrategy,
365	    startVM:
366	      vm?.spec?.runStrategy === RUNSTRATEGY_ALWAYS ||
367	      vm?.spec?.runStrategy === RUNSTRATEGY_RERUNONFAILURE,
368	  };
369	};
370	
371	export default useCreateDrawerForm;

